#!/usr/bin/env node

// This script patches the Claude CLI to fix the unbounded buffer issue
const fs = require('fs');
const path = require('path');

const cliPath = path.join(process.env.HOME, 'node_modules/@anthropic-ai/claude-code/cli.js');

// Read the CLI file
let content = fs.readFileSync(cliPath, 'utf8');

// Find and replace the problematic buffer concatenation
// The issue is in the NU0 function where Q+=I concatenates without bounds
// We'll add a size limit to prevent the RangeError

// First, let's find the exact pattern
const problemPattern = /A\.on\("data",\s*\(I\)\s*=>\s*{\s*if\s*\(B\)\s*B\.write\(I\);\s*else\s*Q\s*\+=\s*I\s*}\)/;

if (problemPattern.test(content)) {
    console.log('Found the problematic code pattern. Applying fix...');

    // Replace with a version that limits buffer size
    content = content.replace(
        problemPattern,
        `A.on("data",(I)=>{if(B)B.write(I);else{if(Q.length>100000000){console.warn("[Claude CLI] Buffer size exceeded 100MB, truncating...");Q=Q.slice(-50000000)}Q+=I}})`
    );

    // Create a backup of the original file
    const backupPath = cliPath + '.backup';
    if (!fs.existsSync(backupPath)) {
        fs.copyFileSync(cliPath, backupPath);
        console.log(`Created backup at ${backupPath}`);
    }

    // Write the patched file
    fs.writeFileSync(cliPath, content);
    console.log('Successfully patched Claude CLI!');
    console.log('The fix limits the buffer to 100MB and keeps the last 50MB when truncating.');
} else {
    console.log('Could not find the exact pattern to patch.');
    console.log('The issue might be in a different format or already fixed.');
}

