/**
 * OrthogonalViewGPU Component Tests
 * Tests for the migrated OrthogonalViewGPU component using the new architecture
 */
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import OrthogonalViewGPU from './OrthogonalViewGPU.svelte';
import { createMockDIContainer, setupMockServices } from '@test-utils';
import { createMockEventBus } from '@test-utils';
import { createMockCrosshairStore, createMockLayerStore } from '@test-utils';
import { flushPromises } from '@test-utils';
import type { VolumeLayerGpuInfo } from '@brainflow/api';

// Mock canvas helper from test setup
import { createMockCanvas } from '../../test-utils/setup/vitest-setup';

// Mock the DI container
vi.mock('$lib/di/Container', () => ({
  getService: vi.fn()
}));

// Mock the stores with their actual exports
vi.mock('$lib/stores/crosshairSlice', () => ({
  useCrosshairStore: {
    subscribe: vi.fn(),
    getState: vi.fn()
  }
}));

vi.mock('$lib/stores/layerStore', () => ({
  useLayerStore: {
    subscribe: vi.fn(),
    getState: vi.fn()
  }
}));

describe('OrthogonalViewGPU', () => {
  let container: ReturnType<typeof createMockDIContainer>;
  let eventBus: ReturnType<typeof createMockEventBus>;
  let crosshairStore: ReturnType<typeof createMockCrosshairStore>;
  let layerStore: ReturnType<typeof createMockLayerStore>;
  let getService: any;
  let mockLayerService: any;
  let mockCrosshairService: any;
  let mockGpuResourceService: any;

  const mockGpuInfo: VolumeLayerGpuInfo = {
    texture_view: 'mock-texture-view',
    width: 512,
    height: 512,
    depth: 100,
    format: 'rgba8unorm'
  };

  beforeEach(() => {
    // Set up mocks
    container = createMockDIContainer();
    eventBus = createMockEventBus();
    const services = setupMockServices(container);

    // Create mock stores
    crosshairStore = createMockCrosshairStore();
    layerStore = createMockLayerStore();

    // Set initial crosshair state
    crosshairStore.setState({
      worldCoord: [0, 0, 0],
      voxelCoord: [128, 128, 50],
      visible: true
    });

    // Set initial layer state
    layerStore.setState({
      activeLayerId: 'layer-1',
      layers: new Map([
        ['layer-1', {
          id: 'layer-1',
          spec: { 
            Volume: { 
              id: 'layer-1', 
              source_resource_id: 'volume-1',
              opacity: 1.0,
              colormap: 'grayscale'
            } 
          },
          gpuInfo: mockGpuInfo,
          isLoadingGpu: false
        }]
      ])
    });

    // Mock layer service
    mockLayerService = {
      requestGpuResources: vi.fn().mockResolvedValue(mockGpuInfo),
      releaseGpuResources: vi.fn().mockResolvedValue(undefined),
      updateLayer: vi.fn().mockResolvedValue(undefined),
      getActiveLayer: vi.fn().mockReturnValue(layerStore.getState().getLayer('layer-1'))
    };

    // Mock crosshair service
    mockCrosshairService = {
      setWorldCoord: vi.fn(),
      setVoxelCoord: vi.fn(),
      getWorldCoord: vi.fn().mockReturnValue([0, 0, 0]),
      getVoxelCoord: vi.fn().mockReturnValue([128, 128, 50])
    };

    // Mock GPU resource service
    mockGpuResourceService = {
      acquireRenderTarget: vi.fn().mockResolvedValue({
        texture: 'mock-render-texture',
        view: 'mock-render-view'
      }),
      releaseRenderTarget: vi.fn(),
      scheduleRender: vi.fn(),
      render: vi.fn().mockResolvedValue(undefined)
    };

    // Mock store implementations
    const { useCrosshairStore } = require('$lib/stores/crosshairSlice');
    crosshairSliceClean.subscribe.mockImplementation(crosshairStore.subscribe);
    crosshairSliceClean.getState.mockImplementation(crosshairStore.getState);

    const { useLayerStore } = require('$lib/stores/layerStore');
    layerStoreClean.subscribe.mockImplementation(layerStore.subscribe);
    layerStoreClean.getState.mockImplementation(layerStore.getState);

    // Mock canvas creation
    HTMLCanvasElement.prototype.getContext = vi.fn().mockReturnValue({
      canvas: createMockCanvas()
    });

    // Set up DI container mock
    getService = require('$lib/di/Container').getService;
    getService.mockImplementation(async (name: string) => {
      switch (name) {
        case 'layerService':
          return mockLayerService;
