/**
 * OrthogonalViewGPU Component Tests
 * Tests for the migrated OrthogonalViewGPU component using the new architecture
 */
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import OrthogonalViewGPU from './OrthogonalViewGPU.svelte';
import { createMockDIContainer, setupMockServices } from '@test-utils';
import { createMockEventBus } from '@test-utils';
import { createMockCrosshairStore, createMockLayerStore } from '@test-utils';
import { flushPromises } from '@test-utils';
import type { VolumeLayerGpuInfo } from '@brainflow/api';

// Mock canvas helper from test setup
import { createMockCanvas } from '../../../test-utils/setup/vitest-setup';

// Mock the DI container
vi.mock('$lib/di/Container', () => ({
  getService: vi.fn()
}));

// Import the stores to be mocked
import { useCrosshairStore } from '$lib/stores/crosshairSlice';
import { useLayerStore } from '$lib/stores/layerStore';

// Mock the stores with their actual exports
vi.mock('$lib/stores/crosshairSlice', () => ({
  useCrosshairStore: {
    subscribe: vi.fn(),
    getState: vi.fn()
  }
}));

vi.mock('$lib/stores/layerStore', () => ({
  useLayerStore: {
    subscribe: vi.fn(),
    getState: vi.fn()
  }
}));

describe('OrthogonalViewGPU', () => {
  let container: ReturnType<typeof createMockDIContainer>;
  let eventBus: ReturnType<typeof createMockEventBus>;
  let crosshairStore: ReturnType<typeof createMockCrosshairStore>;
  let layerStore: ReturnType<typeof createMockLayerStore>;
  let getService: any;
  let mockLayerService: any;
  let mockCrosshairService: any;
  let mockGpuResourceService: any;

  const mockGpuInfo: VolumeLayerGpuInfo = {
    texture_view: 'mock-texture-view',
    width: 512,
    height: 512,
    depth: 100,
    format: 'rgba8unorm'
  };

  beforeEach(() => {
    // Set up mocks
    container = createMockDIContainer();
    eventBus = createMockEventBus();
    const services = setupMockServices(container);

    // Create mock stores
    crosshairStore = createMockCrosshairStore();
    layerStore = createMockLayerStore();

    // Set initial crosshair state
    crosshairStore.setState({
      worldCoord: [0, 0, 0],
      voxelCoord: [128, 128, 50],
      visible: true
    });

    // Set initial layer state
    layerStore.setState({
      activeLayerId: 'layer-1',
      layers: new Map([
        ['layer-1', {
          id: 'layer-1',
          spec: { 
            Volume: { 
              id: 'layer-1', 
              source_resource_id: 'volume-1',
              opacity: 1.0,
              colormap: 'grayscale'
            } 
          },
          gpuInfo: mockGpuInfo,
          isLoadingGpu: false
        }]
      ])
    });

    // Mock layer service
    mockLayerService = {
      requestGpuResources: vi.fn().mockResolvedValue(mockGpuInfo),
      releaseGpuResources: vi.fn().mockResolvedValue(undefined),
      updateLayer: vi.fn().mockResolvedValue(undefined),
      getActiveLayer: vi.fn().mockReturnValue(layerStore.getState().getLayer('layer-1'))
    };

    // Mock crosshair service
    mockCrosshairService = {
      setWorldCoord: vi.fn(),
      setVoxelCoord: vi.fn(),
      getWorldCoord: vi.fn().mockReturnValue([0, 0, 0]),
      getVoxelCoord: vi.fn().mockReturnValue([128, 128, 50])
    };

    // Mock GPU resource service
    mockGpuResourceService = {
      acquireRenderTarget: vi.fn().mockResolvedValue({
        texture: 'mock-render-texture',
        view: 'mock-render-view'
      }),
      releaseRenderTarget: vi.fn(),
      scheduleRender: vi.fn(),
      render: vi.fn().mockResolvedValue(undefined)
    };

    // Mock store implementations
    vi.mocked(useCrosshairStore).subscribe.mockImplementation(crosshairStore.subscribe);
    vi.mocked(useCrosshairStore).getState.mockImplementation(crosshairStore.getState);

    vi.mocked(useLayerStore).subscribe.mockImplementation(layerStore.subscribe);
    vi.mocked(useLayerStore).getState.mockImplementation(layerStore.getState);

    // Mock canvas creation
    HTMLCanvasElement.prototype.getContext = vi.fn().mockReturnValue({
      canvas: createMockCanvas()
    });

    // Set up DI container mock
    const { getService: mockedGetService } = await import('$lib/di/Container');
    getService = vi.mocked(mockedGetService);
    getService.mockImplementation(async (name: string) => {
      switch (name) {
        case 'layerService':
          return mockLayerService;
        case 'crosshairService':
          return mockCrosshairService;
        case 'gpuResourceService':
          return mockGpuResourceService;
        case 'notificationService':
          return services.mockNotificationService;
        case 'eventBus':
          return eventBus;
        default:
          return container.get(name);
      }
    });
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should render three slice views', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    expect(screen.getByTestId('slice-axial')).toBeInTheDocument();
    expect(screen.getByTestId('slice-coronal')).toBeInTheDocument();
    expect(screen.getByTestId('slice-sagittal')).toBeInTheDocument();
  });

  it('should render crosshairs when visible', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    const crosshairs = screen.getAllByTestId('crosshair');
    expect(crosshairs).toHaveLength(3); // One for each view
  });

  it('should handle click to update crosshair position', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    const axialView = screen.getByTestId('slice-axial');

    // Simulate click on canvas
    const canvas = axialView.querySelector('canvas');
    const clickEvent = new MouseEvent('click', {
      clientX: 256,
      clientY: 256,
      bubbles: true
    });

    fireEvent(canvas!, clickEvent);

    await waitFor(() => {
      expect(mockCrosshairService.setWorldCoord).toHaveBeenCalled();
      expect(eventBus.emit).toHaveBeenCalledWith('crosshair.changed', expect.any(Object));
    });
  });

  it('should handle mouse wheel for slice navigation', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    const axialView = screen.getByTestId('slice-axial');
    const canvas = axialView.querySelector('canvas');

    // Simulate wheel event
    fireEvent.wheel(canvas!, { deltaY: 100 });

    await waitFor(() => {
      expect(mockCrosshairService.setVoxelCoord).toHaveBeenCalled();
      expect(eventBus.emit).toHaveBeenCalledWith('slice.changed', expect.any(Object));
    });
  });

  it('should update when layer changes', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    // Change active layer
    layerStore.setState({ activeLayerId: 'layer-2' });

    // Emit layer change event
    eventBus.emit('layer.activated', { layerId: 'layer-2' });

    await waitFor(() => {
      expect(mockGpuResourceService.scheduleRender).toHaveBeenCalled();
    });
  });

  it('should handle GPU resource errors gracefully', async () => {
    mockGpuResourceService.render.mockRejectedValueOnce(new Error('GPU error'));

    render(OrthogonalViewGPU);
    await flushPromises();

    // Trigger render
    eventBus.emit('render.requested');

    await waitFor(() => {
      expect(container.get('notificationService').error).toHaveBeenCalledWith(
        'GPU rendering error',
        expect.objectContaining({ error: expect.any(Error) })
      );
    });
  });

  it('should handle resize events', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    // Simulate resize
    global.dispatchEvent(new Event('resize'));

    // Wait for debounced resize handler
    await waitFor(() => {
      expect(mockGpuResourceService.scheduleRender).toHaveBeenCalled();
    }, { timeout: 350 });
  });

  it('should toggle crosshair visibility', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    // Press 'c' to toggle crosshair
    fireEvent.keyDown(window, { key: 'c' });

    await waitFor(() => {
      expect(eventBus.emit).toHaveBeenCalledWith('crosshair.toggle');
    });
  });

  it('should handle layer opacity changes', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    // Emit opacity change
    eventBus.emit('layer.opacity.changed', { layerId: 'layer-1', opacity: 0.5 });

    await waitFor(() => {
      expect(mockLayerService.updateLayer).toHaveBeenCalledWith('layer-1', 
        expect.objectContaining({ opacity: 0.5 })
      );
      expect(mockGpuResourceService.scheduleRender).toHaveBeenCalled();
    });
  });

  it('should display coordinate information on hover', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    const axialView = screen.getByTestId('slice-axial');
    const canvas = axialView.querySelector('canvas');

    // Simulate mouse move
    fireEvent.mouseMove(canvas!, {
      clientX: 100,
      clientY: 100
    });

    await waitFor(() => {
      expect(eventBus.emit).toHaveBeenCalledWith('mouse.worldcoord', 
        expect.objectContaining({ coord: expect.any(Object) })
      );
    });
  });

  it('should clean up resources on unmount', async () => {
    const { unmount } = render(OrthogonalViewGPU);
    await flushPromises();

    unmount();

    // Verify cleanup
    expect(mockGpuResourceService.releaseRenderTarget).toHaveBeenCalled();
    expect(mockLayerService.releaseGpuResources).toHaveBeenCalled();
    expect(eventBus.getListenerCount('layer.activated')).toBe(0);
    expect(eventBus.getListenerCount('crosshair.changed')).toBe(0);
  });

  it('should handle synchronized slice updates across views', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    // Click on sagittal view
    const sagittalView = screen.getByTestId('slice-sagittal');
    const canvas = sagittalView.querySelector('canvas');

    fireEvent.click(canvas!, {
      clientX: 200,
      clientY: 200
    });

    await waitFor(() => {
      // Should update all views
      expect(mockGpuResourceService.scheduleRender).toHaveBeenCalledTimes(3);
    });
  });

  it('should show slice index indicators', async () => {
    render(OrthogonalViewGPU);
    await flushPromises();

    // Check for slice indicators
    expect(screen.getByText(/Axial: 50/)).toBeInTheDocument();
    expect(screen.getByText(/Coronal: 128/)).toBeInTheDocument();
    expect(screen.getByText(/Sagittal: 128/)).toBeInTheDocument();
  });
});

