/**
 * OrthogonalViewGPU Component Tests
 * Tests for the migrated OrthogonalViewGPU component using the new architecture
 */
import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/svelte';
import OrthogonalViewGPU from './OrthogonalViewGPU.svelte';
import type { VolumeLayerGpuInfo } from '@brainflow/api';

// Create mock stores that match Zustand interface
const createMockLayerStore = (initialState = {}) => {
  let state = {
    layers: new Map(),
    activeLayerId: null,
    ...initialState
  };

  const listeners = new Set<Function>();

  return {
    getState: () => state,
    subscribe: (listener: Function) => {
      listeners.add(listener);
      listener(state, state);
      return () => listeners.delete(listener);
    },
    setState: (newState: any) => {
      const oldState = state;
      state = { ...state, ...newState };
      listeners.forEach(listener => listener(state, oldState));
    }
  };
};

const createMockCrosshairStore = (initialState = {}) => {
  let state = {
    worldCoord: [0, 0, 0],
    voxelCoord: [128, 128, 50],
    visible: true,
    ...initialState
  };

  const listeners = new Set<Function>();

  return {
    getState: () => state,
    subscribe: (listener: Function) => {
      listeners.add(listener);
      listener(state, state);
      return () => listeners.delete(listener);
    },
    setState: (newState: any) => {
      const oldState = state;
      state = { ...state, ...newState };
      listeners.forEach(listener => listener(state, oldState));
    }
  };
};

// Create mock services
const mockLayerService = {
  requestGpuResources: vi.fn(),
  releaseGpuResources: vi.fn(),
  updateLayer: vi.fn(),
  getActiveLayer: vi.fn()
};

const mockCrosshairService = {
  setWorldCoord: vi.fn(),
  setVoxelCoord: vi.fn(),
  getWorldCoord: vi.fn(() => [0, 0, 0]),
  getVoxelCoord: vi.fn(() => [128, 128, 50])
};

const mockNotificationService = {
  error: vi.fn(),
  warning: vi.fn(),
  info: vi.fn()
};

const mockEventBus = {
  on: vi.fn(() => () => {}),
  off: vi.fn(),
  emit: vi.fn()
};

// Mock the DI container
vi.mock('$lib/di/Container', () => ({
  getService: vi.fn(async (name: string) => {
    switch (name) {
      case 'layerService':
        return mockLayerService;
      case 'crosshairService':
        return mockCrosshairService;
      case 'notificationService':
        return mockNotificationService;
      default:
        return {};
    }
  })
}));

// Mock the event bus
vi.mock('$lib/events/EventBus', () => ({
  getEventBus: () => mockEventBus
}));

// Mock the stores
vi.mock('$lib/stores/layerStore', () => {
  const state = {
    layers: new Map(),
    activeLayerId: null
  };
  const listeners = new Set<Function>();

  return {
    useLayerStore: {
      getState: () => state,
      subscribe: (listener: Function) => {
        listeners.add(listener);
        listener(state, state);
        return () => listeners.delete(listener);
      }
    }
  };
});

vi.mock('$lib/stores/crosshairSlice', () => {
  const state = {
    worldCoord: [0, 0, 0],
    voxelCoord: [128, 128, 50],
    visible: true
  };
  const listeners = new Set<Function>();

  return {
    useCrosshairStore: {
      getState: () => state,
      subscribe: (listener: Function) => {
        listeners.add(listener);
        listener(state, state);
        return () => listeners.delete(listener);
      }
    }
  };
});

// Mock zustandBridge to create proper Svelte stores
vi.mock('$lib/stores/zustandBridge', () => ({
  zustandToReadable: (store: any) => ({
    subscribe: (run: Function) => {
      const unsubscribe = store.subscribe((state: any) => run(state));
      return unsubscribe;
    }
  })
}));

// Mock the API
vi.mock('$lib/api', () => ({
  coreApi: {
    request_layer_gpu_resources: vi.fn(),
    release_layer_gpu_resources: vi.fn(),
    render_ortho_view: vi.fn()
  }
}));

// Mock ViewType
vi.mock('$lib/types/ViewType', () => ({
  ViewType: {
    Axial: 0,
    Coronal: 1,
    Sagittal: 2
  },
  getViewTypeName: (type: number) => ['Axial', 'Coronal', 'Sagittal'][type]
}));

// Mock debounce
vi.mock('$lib/utils/debounce', () => ({
  debounce: (fn: Function) => fn
}));

describe('OrthogonalViewGPU', () => {
  const mockGpuInfo: VolumeLayerGpuInfo = {
    texture_view: 'mock-texture-view',
    width: 512,
    height: 512,
    depth: 100,
    format: 'rgba8unorm'
  };

  beforeEach(() => {
    vi.clearAllMocks();

    // Reset store states
    mockLayerStore.setState({
      layers: new Map([
        ['layer-1', {
          id: 'layer-1',
          spec: { 
            Volume: { 
              id: 'layer-1', 
              source_resource_id: 'volume-1',
              opacity: 1.0,
              colormap: 'grayscale'
            } 
          },
          gpuInfo: mockGpuInfo,
          isLoadingGpu: false
        }]
      ]),
      activeLayerId: 'layer-1'
    });

    // Mock canvas
    HTMLCanvasElement.prototype.getContext = vi.fn(() => ({
      canvas: document.createElement('canvas')
    }));
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should render without errors', async () => {
    const { container } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0 // Axial
      }
    });

    expect(container).toBeTruthy();
    await waitFor(() => {
      expect(mockEventBus.on).toHaveBeenCalled();
    });
  });

  it('should display view type name', async () => {
    render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0 // Axial
      }
    });

    expect(screen.getByText('Axial')).toBeInTheDocument();
  });

  it('should handle layer changes', async () => {
    const { rerender } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0
      }
    });

    // Change to different layer
    await rerender({
      layerId: 'layer-2',
      viewType: 0
    });

    await waitFor(() => {
      expect(mockLayerService.releaseGpuResources).toHaveBeenCalled();
    });
  });

  it('should subscribe to opacity changes', async () => {
    render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0
      }
    });

    await waitFor(() => {
      expect(mockEventBus.on).toHaveBeenCalledWith(
        'layer.opacity.changed',
        expect.any(Function)
      );
    });
  });

  it('should handle resize events', async () => {
    const { container } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0
      }
    });

    // Trigger resize
    const canvas = container.querySelector('canvas');
    expect(canvas).toBeTruthy();

    // Simulate resize observer
    await waitFor(() => {
      expect(mockEventBus.emit).toHaveBeenCalledWith(
        'gpu.initialized',
        expect.any(Object)
      );
    });
  });

  it('should clean up on unmount', async () => {
    const { unmount } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0
      }
    });

    unmount();

    await waitFor(() => {
      expect(mockLayerService.releaseGpuResources).toHaveBeenCalled();
    });
  });
});

