  },
  getViewTypeName: (type: number) => ['Axial', 'Coronal', 'Sagittal'][type]
}));

vi.mock('$lib/utils/debounce', () => ({
  debounce: (fn: Function) => fn
}));

describe('OrthogonalViewGPU', () => {
  const mockGpuInfo: VolumeLayerGpuInfo = {
    texture_view: 'mock-texture-view',
    width: 512,
    height: 512,
    depth: 100,
    format: 'rgba8unorm'
  };

  beforeEach(() => {
    vi.clearAllMocks();

    // Reset store states
    layerStoreState.layers = [{
      id: 'layer-1',
      spec: { 
        Volume: { 
          id: 'layer-1', 
          source_resource_id: 'volume-1',
          opacity: 1.0,
          colormap: 'grayscale'
        } 
      },
      gpu: mockGpuInfo,
      isLoadingGpu: false,
      visible: true,
      opacity: 1.0,
      colormap: 'grayscale',
      windowLevel: { window: 1000, level: 500 }
    }];
    layerStoreState.activeLayerId = 'layer-1';

    // Mock canvas
    HTMLCanvasElement.prototype.getContext = vi.fn(() => ({
      canvas: document.createElement('canvas'),
      getParameter: vi.fn(),
      drawingBufferWidth: 512,
      drawingBufferHeight: 512
    }));

    // Mock ResizeObserver
    global.ResizeObserver = vi.fn().mockImplementation(() => ({
      observe: vi.fn(),
      unobserve: vi.fn(),
      disconnect: vi.fn()
    }));

    // Mock service responses
    mockLayerService.requestGpuResources.mockResolvedValue(mockGpuInfo);
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should render without errors', async () => {
    const { container } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0 // Axial
      }
    });

    expect(container).toBeTruthy();
    await waitFor(() => {
      expect(mockEventBus.on).toHaveBeenCalled();
    });
  });

  it('should display view type name', async () => {
    render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0 // Axial
      }
    });

    await waitFor(() => {
      expect(screen.getByText('Axial')).toBeInTheDocument();
    });
  });

  it('should handle layer changes', async () => {
    const { rerender } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0
      }
    });

    // Add a second layer
    layerStoreState.layers.push({
      id: 'layer-2',
      spec: { 
        Volume: { 
          id: 'layer-2', 
          source_resource_id: 'volume-2',
          opacity: 1.0,
          colormap: 'hot'
        } 
      },
      gpu: mockGpuInfo,
      isLoadingGpu: false,
      visible: true,
      opacity: 1.0,
      colormap: 'hot',
      windowLevel: { window: 1000, level: 500 }
    });

    // Change to different layer
    await rerender({
      layerId: 'layer-2',
      viewType: 0
    });

    await waitFor(() => {
      expect(mockLayerService.releaseGpuResources).toHaveBeenCalled();
    });
  });

  it('should handle null layerId gracefully', async () => {
    const { container } = render(OrthogonalViewGPU, {
      props: {
        layerId: null,
        viewType: 0
      }
    });

    expect(container).toBeTruthy();
    await waitFor(() => {
      expect(screen.getByText('Axial')).toBeInTheDocument();
    });
  });

  it('should clean up on unmount', async () => {
    const { unmount } = render(OrthogonalViewGPU, {
      props: {
        layerId: 'layer-1',
        viewType: 0
      }
    });

    unmount();

    await waitFor(() => {
      expect(mockLayerService.releaseGpuResources).toHaveBeenCalled();
    });
  });
});

